// Farm-to-Grocer MVP - Product Card Component
// Path: components/ProductCard.tsx
// Generated by RJBot Orchestrator
//
// A versatile product card component for displaying farm products with:
// - Multiple layout variants (grid, list, compact)
// - Add to cart functionality
// - Quantity selector
// - Organic/certification badges
// - Farmer info display
// - Responsive design
// - Loading skeleton state

"use client";

import * as React from "react";
import Link from "next/link";
import Image from "next/image";
import { cva, type VariantProps } from "class-variance-authority";
import {
  ShoppingCart,
  Plus,
  Minus,
  Heart,
  Leaf,
  MapPin,
  Star,
  Package,
  Clock,
  Check,
  AlertCircle,
} from "lucide-react";
import { cn, formatCurrency } from "@/lib/utils";
import { Button } from "@/components/ui/Button";
import { Card, CardContent, CardFooter } from "@/components/ui/Card";
import {
  Product,
  ProductCategory,
  ProductUnit,
  ProductCategoryLabels,
  ProductUnitLabels,
} from "@/types";

// ============================================
// PRODUCT CARD VARIANTS
// ============================================

const productCardVariants = cva(
  "group relative overflow-hidden transition-all duration-300",
  {
    variants: {
      variant: {
        grid: "flex flex-col",
        list: "flex flex-row gap-4",
        compact: "flex flex-row gap-3 p-3",
      },
      interactive: {
        true: "cursor-pointer hover:shadow-lg hover:-translate-y-1 hover:border-primary/30",
        false: "",
      },
    },
    defaultVariants: {
      variant: "grid",
      interactive: true,
    },
  }
);

// ============================================
// TYPES & INTERFACES
// ============================================

export interface ProductCardProduct {
  id: string;
  name: string;
  description?: string | null;
  category: ProductCategory;
  unit: ProductUnit;
  pricePerUnit: number;
  minOrderQty: number;
  maxOrderQty?: number | null;
  availableQty: number;
  images: string[];
  isOrganic: boolean;
  harvestDate?: Date | null;
  tags?: string[];
  farmer?: {
    id: string;
    farmName: string;
    city: string;
    state: string;
    rating?: number;
    isVerified?: boolean;
  };
}

export interface ProductCardProps
  extends VariantProps<typeof productCardVariants> {
  /**
   * Product data to display
   */
  product: ProductCardProduct;

  /**
   * Callback when add to cart is clicked
   */
  onAddToCart?: (product: ProductCardProduct, quantity: number) => void;

  /**
   * Callback when favorite is toggled
   */
  onToggleFavorite?: (productId: string) => void;

  /**
   * Whether product is in favorites
   */
  isFavorite?: boolean;

  /**
   * Show quantity selector
   */
  showQuantitySelector?: boolean;

  /**
   * Show farmer info
   */
  showFarmerInfo?: boolean;

  /**
   * Show quick add button (single click add)
   */
  showQuickAdd?: boolean;

  /**
   * Custom className
   */
  className?: string;

  /**
   * Loading state
   */
  isLoading?: boolean;

  /**
   * Disable interactions
   */
  disabled?: boolean;
}

// ============================================
// PRODUCT CARD COMPONENT
// ============================================

export function ProductCard({
  product,
  variant = "grid",
  interactive = true,
  onAddToCart,
  onToggleFavorite,
  isFavorite = false,
  showQuantitySelector = true,
  showFarmerInfo = true,
  showQuickAdd = false,
  className,
  isLoading = false,
  disabled = false,
}: ProductCardProps) {
  const [quantity, setQuantity] = React.useState(product.minOrderQty || 1);
  const [isAdding, setIsAdding] = React.useState(false);
  const [justAdded, setJustAdded] = React.useState(false);

  // Calculate stock status
  const isOutOfStock = product.availableQty <= 0;
  const isLowStock = product.availableQty > 0 && product.availableQty < 10;

  // Get primary image
  const primaryImage = product.images?.[0] || "/images/placeholder-product.jpg";

  // Handle quantity change
  const handleQuantityChange = (delta: number) => {
    const newQty = quantity + delta;
    const minQty = product.minOrderQty || 1;
    const maxQty = product.maxOrderQty || product.availableQty;

    if (newQty >= minQty && newQty <= maxQty) {
      setQuantity(newQty);
    }
  };

  // Handle add to cart
  const handleAddToCart = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (isOutOfStock || disabled || isAdding) return;

    setIsAdding(true);
    try {
      await onAddToCart?.(product, quantity);
      setJustAdded(true);
      setTimeout(() => setJustAdded(false), 2000);
    } finally {
      setIsAdding(false);
    }
  };

  // Handle quick add (single click, minimum quantity)
  const handleQuickAdd = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (isOutOfStock || disabled || isAdding) return;

    setIsAdding(true);
    try {
      await onAddToCart?.(product, product.minOrderQty || 1);
      setJustAdded(true);
      setTimeout(() => setJustAdded(false), 2000);
    } finally {
      setIsAdding(false);
    }
  };

  // Handle favorite toggle
  const handleToggleFavorite = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    onToggleFavorite?.(product.id);
  };

  // Loading skeleton
  if (isLoading) {
    return <ProductCardSkeleton variant={variant} className={className} />;
  }

  // Render based on variant
  if (variant === "compact") {
    return (
      <CompactProductCard
        product={product}
        quantity={quantity}
        onQuantityChange={handleQuantityChange}
        onAddToCart={handleAddToCart}
        isAdding={isAdding}
        justAdded={justAdded}
        isOutOfStock={isOutOfStock}
        disabled={disabled}
        className={className}
      />
    );
  }

  if (variant === "list") {
    return (
      <ListProductCard
        product={product}
        quantity={quantity}
        onQuantityChange={handleQuantityChange}
        onAddToCart={handleAddToCart}
        onToggleFavorite={handleToggleFavorite}
        isFavorite={isFavorite}
        isAdding={isAdding}
        justAdded={justAdded}
        isOutOfStock={isOutOfStock}
        isLowStock={isLowStock}
        showFarmerInfo={showFarmerInfo}
        showQuantitySelector={showQuantitySelector}
        disabled={disabled}
        interactive={interactive}
        className={className}
      />
    );
  }

  // Default: Grid variant
  return (
    <Card
      className={cn(
        productCardVariants({ variant, interactive: interactive && !disabled }),
        isOutOfStock && "opacity-75",
        className
      )}
    >
      {/* Product Image */}
      <Link href={`/products/${product.id}`} className="block">
        <div className="relative aspect-square overflow-hidden rounded-t-lg bg-muted">
          <Image
            src={primaryImage}
            alt={product.name}
            fill
            className="object-cover transition-transform duration-300 group-hover:scale-105"
            sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 25vw"
          />

          {/* Badges */}
          <div className="absolute top-2 left-2 flex flex-col gap-1">
            {product.isOrganic && (
              <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800 dark:bg-green-900/80 dark:text-green-200">
                <Leaf className="h-3 w-3" />
                Organic
              </span>
            )}
            {isLowStock && !isOutOfStock && (
              <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-amber-100 text-amber-800 dark:bg-amber-900/80 dark:text-amber-200">
                <Clock className="h-3 w-3" />
                Low Stock
              </span>
            )}
            {isOutOfStock && (
              <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-red-100 text-red-800 dark:bg-red-900/80 dark:text-red-200">
                <AlertCircle className="h-3 w-3" />
                Out of Stock
              </span>
            )}
          </div>

          {/* Favorite Button */}
          {onToggleFavorite && (
            <button
              onClick={handleToggleFavorite}
              className={cn(
                "absolute top-2 right-2 p-2 rounded-full",
                "bg-white/90 dark:bg-gray-900/90 backdrop-blur-sm",
                "transition-all duration-200",
                "hover:scale-110",
                "focus:outline-none focus:ring-2 focus:ring-primary",
                isFavorite && "text-red-500"
              )}
              aria-label={isFavorite ? "Remove from favorites" : "Add to favorites"}
            >
              <Heart
                className={cn("h-5 w-5", isFavorite && "fill-current")}
              />
            </button>
          )}

          {/* Quick Add Button (on hover) */}
          {showQuickAdd && !isOutOfStock && (
            <button
              onClick={handleQuickAdd}
              disabled={isAdding || disabled}
              className={cn(
                "absolute bottom-2 right-2",
                "p-2 rounded-full",
                "bg-primary text-primary-foreground",
                "opacity-0 group-hover:opacity-100",
                "transition-all duration-200",
                "hover:scale-110",
                "disabled:opacity-50",
                justAdded && "bg-green-500"
              )}
              aria-label="Quick add to cart"
            >
              {justAdded ? (
                <Check className="h-5 w-5" />
              ) : (
                <Plus className="h-5 w-5" />
              )}
            </button>
          )}
        </div>
      </Link>

      {/* Product Info */}
      <CardContent className="flex-1 p-4">
        {/* Category */}
        <p className="text-xs text-muted-foreground uppercase tracking-wide mb-1">
          {ProductCategoryLabels[product.category]}
        </p>

        {/* Name */}
        <Link href={`/products/${product.id}`}>
          <h3 className="font-semibold text-foreground line-clamp-2 hover:text-primary transition-colors">
            {product.name}
          </h3>
        </Link>

        {/* Description */}
        {product.description && (
          <p className="text-sm text-muted-foreground line-clamp-2 mt-1">
            {product.description}
          </p>
        )}

        {/* Farmer Info */}
        {showFarmerInfo && product.farmer && (
          <div className="flex items-center gap-2 mt-3 text-sm text-muted-foreground">
            <MapPin className="h-3.5 w-3.5" />
            <span className="truncate">
              {product.farmer.farmName} • {product.farmer.city}, {product.farmer.state}
            </span>
            {product.farmer.isVerified && (
              <Check className="h-3.5 w-3.5 text-primary flex-shrink-0" />
            )}
          </div>
        )}

        {/* Rating */}
        {product.farmer?.rating && (
          <div className="flex items-center gap-1 mt-2">
            <Star className="h-4 w-4 fill-amber-400 text-amber-400" />
            <span className="text-sm font-medium">{product.farmer.rating.toFixed(1)}</span>
          </div>
        )}

        {/* Price */}
        <div className="mt-3">
          <span className="text-xl font-bold text-primary">
            {formatCurrency(product.pricePerUnit)}
          </span>
          <span className="text-sm text-muted-foreground ml-1">
            / {ProductUnitLabels[product.unit]}
          </span>
        </div>

        {/* Min Order */}
        {product.minOrderQty > 1 && (
          <p className="text-xs text-muted-foreground mt-1">
            Min. order: {product.minOrderQty} {ProductUnitLabels[product.unit]}
          </p>
        )}
      </CardContent>

      {/* Add to Cart Section */}
      <CardFooter className="p-4 pt-0">
        {showQuantitySelector && !isOutOfStock ? (
          <div className="flex items-center gap-2 w-full">
            {/* Quantity Selector */}
            <div className="flex items-center border border-input rounded-md">
              <button
                onClick={(e) => {
                  e.preventDefault();
                  handleQuantityChange(-1);
                }}
                disabled={quantity <= (product.minOrderQty || 1) || disabled}
                className="p-2 hover:bg-accent disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                aria-label="Decrease quantity"
              >
                <Minus className="h-4 w-4" />
              </button>
              <span className="px-3 py-1 min-w-[3rem] text-center font-medium">
                {quantity}
              </span>
              <button
                onClick={(e) => {
                  e.preventDefault();
                  handleQuantityChange(1);
                }}
                disabled={
                  quantity >= (product.maxOrderQty || product.availableQty) ||
                  disabled
                }
                className="p-2 hover:bg-accent disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                aria-label="Increase quantity"
              >
                <Plus className="h-4 w-4" />
              </button>
            </div>

            {/* Add to Cart Button */}
            <Button
              onClick={handleAddToCart}
              disabled={isOutOfStock || disabled || isAdding}
              isLoading={isAdding}
              className="flex-1"
              variant={justAdded ? "success" : "default"}
            >
              {justAdded ? (
                <>
                  <Check className="h-4 w-4 mr-2" />
                  Added!
                </>
              ) : (
                <>
                  <ShoppingCart className="h-4 w-4 mr-2" />
                  Add
                </>
              )}
            </Button>
          </div>
        ) : (
          <Button
            onClick={handleAddToCart}
            disabled={isOutOfStock || disabled || isAdding}
            isLoading={isAdding}
            className="w-full"
            variant={isOutOfStock ? "outline" : justAdded ? "success" : "default"}
          >
            {isOutOfStock ? (
              "Out of Stock"
            ) : justAdded ? (
              <>
                <Check className="h-4 w-4 mr-2" />
                Added to Cart!
              </>
            ) : (
              <>
                <ShoppingCart className="h-4 w-4 mr-2" />
                Add to Cart
              </>
            )}
          </Button>
        )}
      </CardFooter>
    </Card>
  );
}

