function ListProductCard({
  product,
  quantity,
  onQuantityChange,
  onAddToCart,
  onToggleFavorite,
  isFavorite,
  isAdding,
  justAdded,
  isOutOfStock,
  isLowStock,
  showFarmerInfo,
  showQuantitySelector,
  disabled,
  interactive,
  className,
}: ListProductCardProps) {
  const primaryImage = product.images?.[0] || "/images/placeholder-product.jpg";

  return (
    <Card
      className={cn(
        productCardVariants({ variant: "list", interactive: interactive && !disabled }),
        isOutOfStock && "opacity-75",
        className
      )}
    >
      {/* Image */}
      <Link href={`/products/${product.id}`} className="flex-shrink-0">
        <div className="relative w-40 h-40 sm:w-48 sm:h-48 overflow-hidden rounded-l-lg bg-muted">
          <Image
            src={primaryImage}
            alt={product.name}
            fill
            className="object-cover"
            sizes="200px"
          />

          {/* Badges */}
          <div className="absolute top-2 left-2 flex flex-col gap-1">
            {product.isOrganic && (
              <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                <Leaf className="h-3 w-3" />
                Organic
              </span>
            )}
          </div>
        </div>
      </Link>

      {/* Content */}
      <div className="flex-1 p-4 flex flex-col justify-between">
        <div>
          {/* Header */}
          <div className="flex items-start justify-between gap-2">
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-wide">
                {ProductCategoryLabels[product.category]}
              </p>
              <Link href={`/products/${product.id}`}>
                <h3 className="font-semibold text-lg hover:text-primary transition-colors">
                  {product.name}
                </h3>
              </Link>
            </div>

            {/* Favorite */}
            <button
              onClick={onToggleFavorite}
              className={cn(
                "p-2 rounded-full hover:bg-accent transition-colors",
                isFavorite && "text-red-500"
              )}
              aria-label={isFavorite ? "Remove from favorites" : "Add to favorites"}
            >
              <Heart className={cn("h-5 w-5", isFavorite && "fill-current")} />
            </button>
          </div>

          {/* Description */}
          {product.description && (
            <p className="text-sm text-muted-foreground line-clamp-2 mt-1">
              {product.description}
            </p>
          )}

          {/* Farmer Info */}
          {showFarmerInfo && product.farmer && (
            <div className="flex items-center gap-4 mt-2 text-sm text-muted-foreground">
              <span className="flex items-center gap-1">
                <MapPin className="h-3.5 w-3.5" />
                {product.farmer.farmName}
              </span>
              {product.farmer.rating && (
                <span className="flex items-center gap-1">
                  <Star className="h-3.5 w-3.5 fill-amber-400 text-amber-400" />
                  {product.farmer.rating.toFixed(1)}
                </span>
              )}
            </div>
          )}

          {/* Stock Status */}
          {isLowStock && !isOutOfStock && (
            <p className="text-xs text-amber-600 mt-2 flex items-center gap-1">
              <Clock className="h-3 w-3" />
              Only {product.availableQty} left
            </p>
          )}
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between mt-4 gap-4">
          {/* Price */}
          <div>
            <span className="text-2xl font-bold text-primary">
              {formatCurrency(product.pricePerUnit)}
            </span>
            <span className="text-sm text-muted-foreground ml-1">
              / {ProductUnitLabels[product.unit]}
            </span>
          </div>

          {/* Add to Cart */}
          <div className="flex items-center gap-2">
            {showQuantitySelector && !isOutOfStock && (
              <div className="flex items-center border border-input rounded-md">
                <button
                  onClick={(e) => {
                    e.preventDefault();
                    onQuantityChange(-1);
                  }}
                  disabled={quantity <= (product.minOrderQty || 1) || disabled}
                  className="p-1.5 hover:bg-accent disabled:opacity-50 transition-colors"
                >
                  <Minus className="h-4 w-4" />
                </button>
                <span className="px-2 min-w-[2.5rem] text-center text-sm font-medium">
                  {quantity}
                </span>
                <button
                  onClick={(e) => {
                    e.preventDefault();
                    onQuantityChange(1);
                  }}
                  disabled={quantity >= product.availableQty || disabled}
                  className="p-1.5 hover:bg-accent disabled:opacity-50 transition-colors"
                >
                  <Plus className="h-4 w-4" />
                </button>
              </div>
            )}

            <Button
              onClick={onAddToCart}
              disabled={isOutOfStock || disabled || isAdding}
              isLoading={isAdding}
              variant={justAdded ? "success" : "default"}
            >
              {justAdded ? (
                <Check className="h-4 w-4" />
              ) : (
                <ShoppingCart className="h-4 w-4" />
              )}
              <span className="ml-2 hidden sm:inline">
                {isOutOfStock ? "Out of Stock" : justAdded ? "Added!" : "Add"}
              </span>
            </Button>
          </div>
        </div>
      </div>
    </Card>
  );
}

// ============================================
// COMPACT VARIANT COMPONENT
